+    spar.delete_edge(0, 1).unwrap();
+    spar.delete_edge(2, 3).unwrap();
+
+    assert_eq!(spar.full_graph().num_edges(), 8); // 10 - 2
+    assert_eq!(spar.stats().deletions, 2);
+}
